    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        log.LogInformation("Processing reporting query request");

        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        
        string tableName = req.Query["table"];
        string columns = req.Query["columns"];
        string orderBy = req.Query["orderBy"];
        string limit = req.Query["limit"];

        if (string.IsNullOrEmpty(tableName))
        {
            return new BadRequestObjectResult("Table name is required");
        }

        if (string.IsNullOrEmpty(columns))
        {
            columns = "*";
        }

        StringBuilder queryBuilder = new StringBuilder();
        queryBuilder.Append("SELECT ");
        
        if (!string.IsNullOrEmpty(limit))
        {
            queryBuilder.Append($"TOP {limit} ");
        }
        
        queryBuilder.Append($"{columns} FROM {tableName}");

        List<string> whereConditions = new List<string>();
        
        foreach (var param in req.Query)
        {
            if (param.Key == "table" || param.Key == "columns" || param.Key == "orderBy" || param.Key == "limit")
            {
                continue;
            }

            string value = param.Value.ToString();
            
            if (value.Contains(","))
            {
                string[] values = value.Split(',');
                List<string> inValues = new List<string>();
                foreach (var v in values)
                {
                    inValues.Add($"'{v.Trim()}'");
                }
                whereConditions.Add($"{param.Key} IN ({string.Join(",", inValues)})");
            }
            else if (value.StartsWith(">="))
            {
                whereConditions.Add($"{param.Key} >= '{value.Substring(2)}'");
            }
            else if (value.StartsWith("<="))
            {
                whereConditions.Add($"{param.Key} <= '{value.Substring(2)}'");
            }
            else if (value.StartsWith(">"))
            {
                whereConditions.Add($"{param.Key} > '{value.Substring(1)}'");
            }
            else if (value.StartsWith("<"))
            {
                whereConditions.Add($"{param.Key} < '{value.Substring(1)}'");
            }
            else if (value.StartsWith("*") || value.EndsWith("*"))
            {
                string likeValue = value.Replace("*", "%");
                whereConditions.Add($"{param.Key} LIKE '{likeValue}'");
            }
            else
            {
                whereConditions.Add($"{param.Key} = '{value}'");
            }
        }

        if (whereConditions.Count > 0)
        {
            queryBuilder.Append(" WHERE ");
            queryBuilder.Append(string.Join(" AND ", whereConditions));
        }

        if (!string.IsNullOrEmpty(orderBy))
        {
            queryBuilder.Append($" ORDER BY {orderBy}");
        }

        string sqlQuery = queryBuilder.ToString();
        log.LogInformation($"Executing query: {sqlQuery}");

        try
        {
            var results = new List<Dictionary<string, object>>();

            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                
                using (SqlCommand command = new SqlCommand(sqlQuery, connection))
                {
                    command.CommandTimeout = 120;
                    
                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                string columnName = reader.GetName(i);
                                object value = reader.IsDBNull(i) ? null : reader.GetValue(i);
                                row[columnName] = value;
                            }
                            
                            results.Add(row);
                        }
                    }
                }
            }

            return new OkObjectResult(new
            {
                query = sqlQuery,
                count = results.Count,
                data = results
            });
        }
        catch (SqlException ex)
        {
            log.LogError($"SQL Error: {ex.Message}");
            return new StatusCodeResult(500);
        }
        catch (Exception ex)
        {
            log.LogError($"Error: {ex.Message}");
            return new StatusCodeResult(500);
        }
    }

